                    {"type": "quiz", "question": "Какой тип света создаёт самые мягкие и реалистичные тени?", "options": [{"id": "a", "text": "Point Light", "correct": False}, {"id": "b", "text": "Sun Light", "correct": False}, {"id": "c", "text": "Spot Light", "correct": False}, {"id": "d", "text": "Area Light", "correct": True}]},
