                    {"type": "quiz", "question": "Какой режим затенения используется в Low-poly стиле?", "options": [{"id": "a", "text": "Shade Smooth", "correct": False}, {"id": "b", "text": "Shade Flat", "correct": True}, {"id": "c", "text": "Shade Auto", "correct": False}, {"id": "d", "text": "Wireframe", "correct": False}]},
